  "points": [
    {"text": "Measure incoming request rate (RPS) and its 95th percentile burst to size thread pools and socket buffers."},
    {"text": "Track p95 latency per endpoint and correlate with CPU, memory, and queue length to spot saturation early."},
    {"text": "Monitor TCP retransmission count and SYN backlog; high values indicate network congestion or insufficient listen queue."},
    {"text": "Set a circuit‑breaker threshold at ~80% of observed max concurrent connections to stop new traffic before overload."},
    {"text": "Limit client retries: max 2 retries with exponential backoff, and enforce a minimum backoff of 100 ms."},
    {"text": "Configure connection timeout to 2 s and read timeout to 5 s; adjust down if p95 latency budget is <200 ms."},
    {"text": "Enable keep‑alive with idle timeout ~30 s to recycle idle sockets and avoid resource exhaustion."}
  ]
}

